{
  "grammar": [
    {
      "pattern": "請問 + place + 怎麼走？",
      "structure": ["question phrase", "place", "direction query"],
      "explanation_en": "Use this polite question to ask for directions to a place. '請問' makes it polite, and '怎麼走' asks 'how to go'.",
      "title": "Asking for Directions Politely",
      "meaning": "Excuse me, how do I get to [place]?",
      "when_to_use": ["When you are lost or need directions", "When you want to be polite in Taiwan"],
      "when_not_to_use": ["When you are in a hurry and need a quick answer", "When you already know the way"],
      "pragmatic_notes": "In Taiwan, always start with '請問' to show respect. People are generally helpful and will give detailed directions.",
      "word_order_notes": "Place comes after '請問' and before '怎麼走'.",
      "english_contrast": "In English, you might say 'How do I get to...?' but in Chinese, the polite form '請問' is essential.",
      "korean_contrast": "In Korean, you might say '...에 어떻게 가나요?' but the polite prefix '請問' is unique to Chinese.",
      "negative_examples": [
        {
          "text": "怎麼走車站？",
          "error": "Missing '請問' and incorrect word order; place should come before '怎麼走'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "車站怎麼走？",
          "error": "This is grammatically correct but less polite without '請問'."
        }
      ],
      "transformation_drills": ["Change '車站' to '公園' and ask the question.", "Ask for directions to '醫院' using the pattern."],
      "production_drills": ["Ask a classmate how to get to the library.", "Role-play asking a stranger for directions to a store."],
      "common_error_patterns": ["Forgetting '請問'", "Placing '怎麼走' before the place"],
      "repair_feedback": {
        "word_order": "Remember: 請問 + place + 怎麼走？",
        "politeness": "Always use '請問' to be polite.",
        "vocabulary": "Use the correct place name."
      }
    },
    {
      "pattern": "Subject + 想 + 買 + object + 多少錢？",
      "structure": ["subject", "verb", "object", "price query"],
      "explanation_en": "Use this to express a desire to buy something and ask for its price. '想' indicates a wish, and '多少錢' asks 'how much money'.",
      "title": "Expressing Desire to Buy and Asking Price",
      "meaning": "I want to buy [object], how much is it?",
      "when_to_use": ["When shopping and you want to know the price", "When you are interested in an item"],
      "when_not_to_use": ["When you are not buying anything", "When the price is already displayed"],
      "pragmatic_notes": "In Taiwan, it's common to ask the price directly. You can also say '這個多少錢？' for 'this'.",
      "word_order_notes": "Subject comes first, then '想', then '買', then object, then '多少錢'.",
      "english_contrast": "In English, you might say 'How much is this?' but in Chinese, you specify the action '想買'.",
      "korean_contrast": "In Korean, you might say '이거 얼마예요?' but the verb '想買' is explicit in Chinese.",
      "negative_examples": [
        {
          "text": "我買書多少錢？",
          "error": "Missing '想' which indicates the desire to buy."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想買書多少錢？",
          "error": "This is correct but can be shortened to '這個多少錢？' if the item is clear."
        }
      ],
      "transformation_drills": ["Change '書' to '手機' and ask the price.", "Ask for the price of '水' using the pattern."],
      "production_drills": ["Ask a shopkeeper the price of a cup of coffee.", "Role-play buying a book and asking its price."],
      "common_error_patterns": ["Omitting '想'", "Using '多少' instead of '多少錢'"],
      "repair_feedback": {
        "word_order": "Subject + 想 + 買 + object + 多少錢？",
        "politeness": "Adding '請問' at the beginning makes it more polite.",
        "vocabulary": "Use '多少錢' for price, not just '多少'."
      }
    },
    {
      "pattern": "Subject + 在 + place + 買東西 + 嗎？",
      "structure": ["subject", "location marker", "place", "action", "question particle"],
      "explanation_en": "Use this to ask if someone is shopping at a specific place. '在' indicates ongoing action, and '嗎' turns it into a question.",
      "title": "Asking About Shopping Activity",
      "meaning": "Are you shopping at [place]?",
      "when_to_use": ["When you see someone at a store and want to confirm", "When making small talk about shopping"],
      "when_not_to_use": ["When the person is not shopping", "When you are sure about their activity"],
      "pragmatic_notes": "In Taiwan, this is a common small talk question. It shows interest in the other person's activities.",
      "word_order_notes": "Subject first, then '在', then place, then '買東西', then '嗎'.",
      "english_contrast": "In English, you might say 'Are you shopping at the store?' but in Chinese, the location comes before the action.",
      "korean_contrast": "In Korean, you might say '가게에서 쇼핑하세요?' but the structure is similar with '에서' for location.",
      "negative_examples": [
        {
          "text": "你買東西在商店嗎？",
          "error": "Incorrect word order; '在' should come before the place."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你在商店買東西嗎？",
          "error": "This is correct but '買東西' can be replaced with a specific item like '買書'."
        }
      ],
      "transformation_drills": ["Change '商店' to '夜市' and ask the question.", "Ask if someone is buying '水果' at the market."],
      "production_drills": ["Ask a friend if they are shopping at the convenience store.", "Role-play asking a neighbor about their shopping at the supermarket."],
      "common_error_patterns": ["Placing '在' after the place", "Omitting '嗎' for questions"],
      "repair_feedback": {
        "word_order": "Subject + 在 + place + 買東西 + 嗎？",
        "politeness": "Using '你' is fine for friends; for strangers, use '您' or add '請問'.",
        "vocabulary": "Use '買東西' for general shopping or specify the item."
      }
    }
  ]
}
